namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<NotificationItem> _notifications = new()
    {
        new() { Id = 1, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
        new() { Id = 2, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
        new() { Id = 3, Message = "New feature available: Dark Mode.", Timestamp = DateTime.UtcNow.AddMinutes(-1) },
    };

    private static readonly string[] SampleMessages =
    [
        "Someone commented on your post.",
        "You have a new follower.",
        "Your report is ready to download.",
        "Scheduled maintenance tonight at 11 PM.",
        "A new version of the app is available.",
    ];

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
    }

    public Task<List<NotificationItem>> CheckForNewAsync(DateTime since)
    {
        // Simulate occasional new notifications
        if (Random.Shared.Next(3) == 0)
        {
            var item = new NotificationItem
            {
                Id = _nextId++,
                Message = SampleMessages[Random.Shared.Next(SampleMessages.Length)],
                Timestamp = DateTime.UtcNow,
            };
            _notifications.Add(item);
        }

        var newer = _notifications
            .Where(n => n.Timestamp > since)
            .OrderByDescending(n => n.Timestamp)
            .ToList();

        return Task.FromResult(newer);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (Items is not null)
    {
        <span class="badge bg-primary ms-2">@Items.Count</span>
    }
</h1>

@if (Items is null)
{
    <p><em>Loading notifications...</em></p>
}
else if (Items.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var item in Items)
        {
            <li class="list-group-item">
                <strong>@item.Message</strong>
                <small class="text-muted ms-2">@item.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? Items { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not restored from prerender state
        Items ??= await NotificationService.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender never fires during prerender, so this only runs
            // once the page is live and interactive.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var since = Items?.Max(n => n.Timestamp) ?? DateTime.MinValue;
            var newer = await NotificationService.CheckForNewAsync(since);

            if (newer.Count > 0 && Items is not null)
            {
                Items = newer.Concat(Items).ToList();
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

